class Solution:
    def splitIntoFibonacci(self, num: str) -> List[int]:
        def dfs(nums, idx):
            if idx >= len(num):
                return True
            for i in range(1, 12):
                if idx + i <= len(num) and int(num[idx:idx+i]) <= 2**31 - 1:
                    if dfs(nums + [int(num[idx:idx+i])], idx + i):
                        return True
            return False

        for i in range(1, min(11, len(num))):
            if int(num[:i]) <= 2**31 - 1:
                if dfs([int(num[:i])], i):
                    return [int(num[:i])] + nums
        return []
```

